def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.5
            elif j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.7
            score += term
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 2.5
            for k in range(1, 5):
                if remaining < k * 0.01 * capacity:
                    score += 0.1 * k * np.sqrt(item)
        elif remaining < 0.2 * capacity:
            score *= 1.4
            if i > 0 and bins[i-1] > capacity:
                score *= 1.2
            elif i < len(bins) - 1 and bins[i+1] < capacity:
                score *= 0.85
        else:
            decay = 1.0
            for m in range(1, 6):
                if remaining > m * 0.15 * capacity:
                    decay *= 0.85
            score *= decay
        if item > 0.6 * capacity:
            score += np.log1p(item) * 0.5
        if i % 2 == 0:
            score *= 1.05
        else:
            score *= 0.95
        if i > 1:
            prev_diff = abs(bins[i-1] - capacity)
            prev2_diff = abs(bins[i-2] - capacity)
            if prev_diff < prev2_diff:
                score *= 1.1
            else:
                score *= 0.9
        if score < 0.05:
            score += 0.02 * np.cos(i * item)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    for i in range(len(priorities)):
        if priorities[i] < 0.3:
            priorities[i] += 0.15 * np.sin(i * item * 0.5)
    return priorities
